import { AnimatePresence, motion } from 'framer-motion'

// Floatender XP-Toast nach jedem Bewertungs-Event. Zeigt base XP, Multiplikator
// (falls > 1) und total awarded XP. Auto-disappear nach ~1.2s.

export type XpToastData = {
  id: number
  base: number
  multiplier: number
  awarded: number
}

export function XPToast({ toast }: { toast: XpToastData | null }) {
  return (
    <AnimatePresence>
      {toast && (
        <motion.div
          key={toast.id}
          initial={{ opacity: 0, y: 30, scale: 0.85 }}
          animate={{ opacity: 1, y: 0, scale: 1 }}
          exit={{ opacity: 0, y: -20, scale: 0.95 }}
          transition={{ duration: 0.3, ease: 'easeOut' }}
          style={{
            position: 'fixed',
            top: '12vh',
            left: '50%',
            transform: 'translateX(-50%)',
            zIndex: 60,
            background: 'var(--green)',
            color: 'var(--cream)',
            padding: '0.7rem 1.2rem',
            borderRadius: 999,
            boxShadow: '0 8px 24px rgba(62, 90, 10, 0.35)',
            fontWeight: 700,
            letterSpacing: '0.5px',
            fontSize: '1rem',
            display: 'flex',
            alignItems: 'baseline',
            gap: 8,
            pointerEvents: 'none'
          }}
        >
          <span>+{toast.awarded} XP</span>
          {toast.multiplier > 1 && (
            <span style={{ fontSize: '0.75rem', opacity: 0.85 }}>
              ×{toast.multiplier.toFixed(1)}
            </span>
          )}
        </motion.div>
      )}
    </AnimatePresence>
  )
}
