import { supabase } from './supabase'
import { levelFromXp, rankFromLevel } from './levels'
import { useNotificationStore } from '@/store/useNotificationStore'
import { checkAchievementsAfterXp } from './achievements'

// XP-Vergabe für Virág laut CLAUDE.md §8.
//
// Verhalten:
//   1. Streak-Multiplikator anwenden (×1.0..×2.0 je nach current_streak)
//   2. xp_event INSERT
//   3. profiles.app_xp.virag JSONB-Update
//   4. Level berechnen — wenn höher als zuvor: profiles.level + rank update,
//      Level-Up-Overlay triggern
//   5. Achievement-Engine triggern (cards_50, streak_*, etc.)

export type Mode = 'medical' | 'everyday' | 'meta'

export function streakMultiplier(streak: number): number {
  if (streak >= 100) return 2.0
  if (streak >= 30) return 1.5
  if (streak >= 7) return 1.2
  return 1.0
}

export type AwardResult = {
  base: number
  multiplier: number
  awarded: number
  streak: number
}

export async function awardXp(opts: {
  baseAmount: number
  source: string
  mode?: Mode
}): Promise<AwardResult | null> {
  const { baseAmount, source, mode = 'medical' } = opts

  const { data: { user } } = await supabase.auth.getUser()
  if (!user) return null

  // 1) Profile lesen (für Streak + bisheriges app_xp + level)
  const { data: profile } = await supabase
    .from('profiles')
    .select('current_streak, app_xp, level')
    .eq('id', user.id)
    .single()

  const streak = (profile?.current_streak as number) ?? 0
  const multiplier = streakMultiplier(streak)
  const awarded = Math.round(baseAmount * multiplier)

  const currentApp = (profile?.app_xp as Record<string, number> | null) ?? {}
  const nextApp = { ...currentApp, virag: (currentApp.virag ?? 0) + awarded }
  // Total XP = Summe aller App-XPs
  const nextTotal = Object.values(nextApp).reduce((s, v) => s + (Number(v) || 0), 0)
  const prevLevel = (profile?.level as number) ?? 1
  const newLevel = levelFromXp(nextTotal)
  const newRank = rankFromLevel(newLevel)

  // 2+3) xp_event Insert + profiles update parallel
  const updates: Record<string, unknown> = { app_xp: nextApp }
  if (newLevel !== prevLevel) {
    updates.level = newLevel
    updates.rank = newRank.rankHu
  }

  await Promise.all([
    supabase.from('xp_events').insert({
      user_id: user.id,
      app: 'virag',
      mode,
      xp_amount: awarded,
      source,
      metadata: { base: baseAmount, multiplier }
    }),
    supabase.from('profiles').update(updates).eq('id', user.id)
  ])

  // 4) Level-Up Overlay
  if (newLevel > prevLevel) {
    useNotificationStore.getState().pushLevelUp({
      fromLevel: prevLevel,
      toLevel: newLevel,
      rankHu: newRank.rankHu,
      rankDe: newRank.rankDe
    })
  }

  // 5) Achievement-Check (lazy, ohne await — soll Game-Loop nicht blocken)
  void checkAchievementsAfterXp(user.id, source)

  return { base: baseAmount, multiplier, awarded, streak }
}
